import requests
import math
from python.config import CONFIG

def ollama_request(endpoint, body):
    try:
        url = f"{CONFIG['OLLAMA_BASE_URL']}/{endpoint}"
        res = requests.post(url, json=body, headers={"Content-Type": "application/json"})
        
        if not res.ok:
            raise Exception(f"Ollama error ({res.status_code}): {res.text}")
            
        return res.json()
    except Exception as error:
        print(f"Ollama API error ({endpoint}): {error}")
        raise error

def chat(messages, tools=None):
    payload = {
        "model": CONFIG["CHAT_MODEL"],
        "messages": messages,
        "stream": False
    }
    if tools and len(tools) > 0 and "phi" not in CONFIG["CHAT_MODEL"].lower():
        payload["tools"] = tools
        
    data = ollama_request("chat", payload)
    return data.get("message")

def get_embedding(text):
    data = ollama_request("embeddings", {
        "model": CONFIG["EMBED_MODEL"],
        "prompt": text
    })
    return data.get("embedding")

def cosine_similarity(a, b):
    dot = sum(x * y for x, y in zip(a, b))
    mag_a = math.sqrt(sum(x * x for x in a))
    mag_b = math.sqrt(sum(y * y for y in b))
    
    if mag_a * mag_b == 0:
        return 0
        
    return dot / (mag_a * mag_b)
